const express = require('express');
const multer = require('multer');
const path = require('path');
const fs = require('fs');
const crypto = require('crypto');
const sharp = require('sharp');
const AdmZip = require('adm-zip');

const router = express.Router();

const uploadDir = path.join(process.cwd(), 'public', 'uploads');
const thumbDir = path.join(uploadDir, 'thumbnails');

fs.mkdirSync(uploadDir, { recursive: true });
fs.mkdirSync(thumbDir, { recursive: true });

const allowedMimeTypes = new Set([
  'image/jpeg',
  'image/png',
  'image/gif',
  'image/svg+xml',
  'application/pdf',
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/zip',
  'application/x-zip-compressed'
]);

const allowedExtensions = new Set([
  '.jpg',
  '.jpeg',
  '.png',
  '.gif',
  '.svg',
  '.pdf',
  '.doc',
  '.docx',
  '.zip'
]);

function sanitizeFilename(name) {
  const ext = path.extname(name).toLowerCase();
  const base = path
    .basename(name, ext)
    .replace(/[^a-zA-Z0-9-_]/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 80) || 'file';
  const unique = `${Date.now()}-${crypto.randomBytes(8).toString('hex')}`;
  return `${base}-${unique}${ext}`;
}

function isEnterpriseUser(req) {
  return Boolean(req.user && (req.user.role === 'enterprise' || req.user.plan === 'enterprise'));
}

function getMaxFileSize(req) {
  return isEnterpriseUser(req) ? Infinity : 25 * 1024 * 1024;
}

function fileFilter(req, file, cb) {
  const ext = path.extname(file.originalname).toLowerCase();
  if (!allowedExtensions.has(ext)) return cb(new Error('Unsupported file type'));
  if (file.mimetype && !allowedMimeTypes.has(file.mimetype)) return cb(new Error('Unsupported file type'));
  cb(null, true);
}

const storage = multer.diskStorage({
  destination(req, file, cb) {
    cb(null, uploadDir);
  },
  filename(req, file, cb) {
    cb(null, sanitizeFilename(file.originalname));
  }
});

function createUploader(req) {
  return multer({
    storage,
    fileFilter,
    limits: {
      fileSize: getMaxFileSize(req)
    }
  });
}

async function generateThumbnail(filePath, filename) {
  const ext = path.extname(filename).toLowerCase();
  const thumbName = `${path.basename(filename, ext)}.jpg`;
  const thumbPath = path.join(thumbDir, thumbName);

  if (ext === '.svg') {
    const svgBuffer = fs.readFileSync(filePath);
    await sharp(svgBuffer).resize(300, 300, { fit: 'inside' }).jpeg({ quality: 85 }).toFile(thumbPath);
    return thumbName;
  }

  await sharp(filePath).resize(300, 300, { fit: 'inside' }).jpeg({ quality: 85 }).toFile(thumbPath);
  return thumbName;
}

router.post('/upload', (req, res) => {
  const uploader = createUploader(req).single('file');

  uploader(req, res, async (err) => {
    if (err) {
      return res.status(400).json({ error: err.message });
    }

    if (!req.file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    const fileUrl = `/uploads/${req.file.filename}`;
    let thumbnailUrl = null;

    try {
      const ext = path.extname(req.file.filename).toLowerCase();
      if (['.jpg', '.jpeg', '.png', '.gif', '.svg'].includes(ext)) {
        const thumbName = await generateThumbnail(req.file.path, req.file.filename);
        thumbnailUrl = `/uploads/thumbnails/${thumbName}`;
      }

      if (ext === '.zip') {
        try {
          const zip = new AdmZip(req.file.path);
          zip.getEntries();
        } catch (_) {}
      }

      return res.status(201).json({
        success: true,
        file: {
          originalName: req.file.originalname,
          filename: req.file.filename,
          url: fileUrl,
          thumbnailUrl,
          mimetype: req.file.mimetype,
          size: req.file.size
        }
      });
    } catch (e) {
      try {
        fs.unlinkSync(req.file.path);
      } catch (_) {}
      return res.status(500).json({ error: 'Failed to process uploaded file' });
    }
  });
});

module.exports = router;